package main

import (
	"context"
	"fmt"
)

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	cancel()
	select {
	case <-ctx.Done(): fmt.Println("stopped", ctx.Err())
	default: fmt.Println("still running")
	}
}
